#include<bits/stdc++.h>
using namespace std;
int d, b;
int dx[8] = {1, 0, -1, 0};
int dy[8] = {0, 1, 0, -1};
int a[511][511],v[501][501];
int n, m;
void dfs(int x, int y) {
    v[x][y]=-1;
	for (int i = 0; i < 4; i++) {
		int mx = dx[i] + x;
		int my = dy[i] + y;
		if(!v[mx][my]&&a[mx][my]==0)	a[mx][my] = -1*(a[x][y] + 1);
	}
}
int main() {
	cin >> n >> m >> d >> b;

	for (int i = 1; i <= d; i++) {
		int x, y;
		cin >> x >> y;
		a[x][y] = 1;
	}

	for (int k = 1; k <= n * 2 + 1; k++) {
		for (int i = 1; i <= n; i++) {
			for (int j = 1; j <= m; j++) {
				if (a[i][j] >= 1&& v[i][j]!=1) {
					dfs(i, j);
				}
			}
		}
        for (int i = 1; i <= n; i++) {
			for (int j = 1; j <= m; j++) {
				if (a[i][j] < 0) {
					a[i][j]=-a[i][j];

				}
                if(v[i][j]==-1){
                    v[i][j]=1;
                }
			}
		}
	}

	for (int i = 1; i <= b; i++) {
			int x,y;
        cin>>x>>y;
        cout<<a[x][y]-1<<"\n";
	}
}
